# frozen_string_literal: true\n\nrequire 'rails_helper'\n\nRSpec.describe Jdpi::MedService, type: :service do\n  let(:valid_end_to_end_id) { \"E00038166201907261559y6j6mt9l0pi\" }\n  let(:valid_refund_amount) { 150.85 }\n  let(:valid_refund_code) { \"MD06\" }\n  let(:refund_description) { \"Refund requested by customer\" }\n  let(:client_info) { \"Customer satisfaction refund\" }\n  \n  let(:service) do\n    described_class.new(\n      end_to_end_id_original: valid_end_to_end_id,\n      refund_amount: valid_refund_amount,\n      refund_code: valid_refund_code,\n      refund_description: refund_description,\n      client_info: client_info,\n      client_authorization_token: \"valid_jwt_token\"\n    )\n  end\n\n  before do\n    # Mock JDPI API responses\n    allow_any_instance_of(Jdpi::BaseService).to receive(:execute_request).and_return({\n      \"idReqSistemaCliente\" => \"69F963C6-7487-4363-9406-A1DE2A9636D4\",\n      \"idReqJdPi\" => \"70F945C1-9024-4123-1001-A1DE2A0000D1\",\n      \"endToEndIdOriginal\" => valid_end_to_end_id,\n      \"endToEndIdDevolucao\" => \"D00038166202007261051y0j8mt5l3pi\",\n      \"dtHrReqJdPi\" => \"2025-01-23T22:10:05.025Z\"\n    })\n  end\n\n  describe \"#call\" do\n    context \"with valid parameters\" do\n      it \"processes MED refund successfully\" do\n        result = service.call\n        \n        expect(result[:success]).to be true\n        expect(result[:data]).to include(\"idReqJdPi\")\n        expect(result[:errors]).to be_empty\n      end\n      \n      it \"logs the refund processing\" do\n        expect(Rails.logger).to receive(:info).with(/Processing MD06 refund/)\n        service.call\n      end\n    end\n\n    context \"with invalid EndToEndId format\" do\n      let(:valid_end_to_end_id) { \"INVALID_FORMAT\" }\n      \n      it \"fails validation\" do\n        result = service.call\n        \n        expect(result[:success]).to be false\n        expect(result[:errors].first).to include(\"Validation failed\")\n      end\n    end\n\n    context \"with missing client authorization for MD06\" do\n      let(:service) do\n        described_class.new(\n          end_to_end_id_original: valid_end_to_end_id,\n          refund_amount: valid_refund_amount,\n          refund_code: valid_refund_code\n          # Missing client_authorization_token\n        )\n      end\n      \n      it \"fails compliance validation\" do\n        result = service.call\n        \n        expect(result[:success]).to be false\n        expect(result[:errors].first).to include(\"Validation failed\")\n      end\n    end\n\n    context \"with FR01 fraud refund\" do\n      let(:valid_refund_code) { \"FR01\" }\n      let(:service) do\n        described_class.new(\n          end_to_end_id_original: valid_end_to_end_id,\n          refund_amount: valid_refund_amount,\n          refund_code: valid_refund_code,\n          client_authorization_token: \"valid_jwt_token\",\n          fraud_analysis_data: { risk_score: 0.8, detected_patterns: [\"unusual_velocity\"] }\n        )\n      end\n      \n      it \"processes fraud suspicion refund\" do\n        result = service.call\n        \n        expect(result[:success]).to be true\n        expect(result[:data]).to include(\"idReqJdPi\")\n      end\n    end\n\n    context \"with BE08 operational failure\" do\n      let(:valid_refund_code) { \"BE08\" }\n      let(:service) do\n        described_class.new(\n          end_to_end_id_original: valid_end_to_end_id,\n          refund_amount: valid_refund_amount,\n          refund_code: valid_refund_code\n          # No client authorization needed for BE08\n        )\n      end\n      \n      it \"processes operational failure refund without client auth\" do\n        result = service.call\n        \n        expect(result[:success]).to be true\n      end\n    end\n  end\n\n  describe \".query_refund_status\" do\n    let(:jdpi_request_id) { \"70F945C1-9024-4123-1001-A1DE2A0000D1\" }\n    \n    before do\n      allow_any_instance_of(described_class).to receive(:execute_request).and_return({\n        \"idReqJdPiConsultada\" => jdpi_request_id,\n        \"stJdPi\" => 9,\n        \"stJdPiProc\" => 9,\n        \"endToEndIdOriginal\" => valid_end_to_end_id,\n        \"valorDevolucao\" => valid_refund_amount\n      })\n    end\n    \n    it \"queries refund status successfully\" do\n      result = described_class.query_refund_status(jdpi_request_id: jdpi_request_id)\n      \n      expect(result[:success]).to be true\n      expect(result[:data][\"stJdPi\"]).to eq(9)\n    end\n  end\n\n  describe \".list_refund_reasons\" do\n    before do\n      allow_any_instance_of(described_class).to receive(:execute_request).and_return({\n        \"resultado\" => [\n          {\n            \"codigoDevolucao\" => \"BE08\",\n            \"descricao\" => \"Devolução por falha operacional\"\n          },\n          {\n            \"codigoDevolucao\" => \"FR01\", \n            \"descricao\" => \"Devolução por suspeita de fraude\"\n          },\n          {\n            \"codigoDevolucao\" => \"MD06\",\n            \"descricao\" => \"Devolução solicitada pelo usuário\"\n          },\n          {\n            \"codigoDevolucao\" => \"SL02\",\n            \"descricao\" => \"Erro em PIX Saque/Troco\"\n          }\n        ]\n      })\n    end\n    \n    it \"retrieves available refund reasons\" do\n      result = described_class.list_refund_reasons\n      \n      expect(result[:success]).to be true\n      expect(result[:data][\"resultado\"]).to have(4).items\n      expect(result[:data][\"resultado\"].map { |r| r[\"codigoDevolucao\"] }).to contain_exactly(\"BE08\", \"FR01\", \"MD06\", \"SL02\")\n    end\n  end\n\n  describe \"refund code normalization\" do\n    it \"normalizes lowercase refund codes\" do\n      service = described_class.new(\n        end_to_end_id_original: valid_end_to_end_id,\n        refund_amount: valid_refund_amount,\n        refund_code: \"md06\"\n      )\n      \n      expect(service.refund_code).to eq(\"MD06\")\n    end\n    \n    it \"normalizes symbolic refund codes\" do\n      service = described_class.new(\n        end_to_end_id_original: valid_end_to_end_id,\n        refund_amount: valid_refund_amount,\n        refund_code: \"fr01\"\n      )\n      \n      expect(service.refund_code).to eq(\"FR01\")\n    end\n  end\n\n  describe \"EndToEndId generation\" do\n    it \"generates valid refund EndToEndId\" do\n      allow(SecureRandom).to receive(:alphanumeric).and_return(\"y0j8mt5l3pi\")\n      allow(Time).to receive(:current).and_return(Time.parse(\"2025-07-26 10:51:00 UTC\"))\n      \n      refund_id = service.send(:generate_refund_end_to_end_id)\n      \n      expect(refund_id).to eq(\"D00038166202507261051y0j8mt5l3pi\")\n      expect(refund_id).to start_with(\"D\") # Refund prefix\n      expect(refund_id.length).to eq(32)\n    end\n  end\n\n  describe \"compliance validations\" do\n    context \"for different refund codes\" do\n      it \"validates BE08 requires no client authorization\" do\n        service = described_class.new(\n          end_to_end_id_original: valid_end_to_end_id,\n          refund_amount: valid_refund_amount,\n          refund_code: \"BE08\"\n        )\n        \n        expect(service).to be_valid\n      end\n      \n      it \"validates FR01 requires fraud analysis data\" do\n        service = described_class.new(\n          end_to_end_id_original: valid_end_to_end_id,\n          refund_amount: valid_refund_amount,\n          refund_code: \"FR01\",\n          client_authorization_token: \"valid_token\"\n          # Missing fraud_analysis_data\n        )\n        \n        expect(service).not_to be_valid\n        expect(service.errors[:fraud_analysis_data]).to include(/required for FR01/)\n      end\n      \n      it \"validates MD06 requires client authorization\" do\n        service = described_class.new(\n          end_to_end_id_original: valid_end_to_end_id,\n          refund_amount: valid_refund_amount,\n          refund_code: \"MD06\"\n          # Missing client_authorization_token\n        )\n        \n        expect(service).not_to be_valid\n        expect(service.errors[:client_authorization_token]).to include(/required for MD06/)\n      end\n    end\n  end\n\n  describe \"amount validations\" do\n    before do\n      # Mock original transaction with remaining balance\n      allow(service).to receive(:original_transaction).and_return({\n        amount: 1000.0,\n        created_at: 30.days.ago,\n        refunded_amount: 300.0, # Already refunded R$ 300\n        transaction_type: \"payment\"\n      })\n    end\n    \n    it \"validates refund amount doesn't exceed remaining balance\" do\n      service.refund_amount = 800.0 # Would exceed remaining R$ 700\n      \n      expect(service).not_to be_valid\n      expect(service.errors[:refund_amount]).to include(/exceeds remaining balance/)\n    end\n    \n    it \"allows refund within remaining balance\" do\n      service.refund_amount = 600.0 # Within remaining R$ 700\n      \n      expect(service).to be_valid\n    end\n  end\n\n  describe \"90-day refund window validation\" do\n    before do\n      allow(service).to receive(:original_transaction).and_return({\n        amount: 1000.0,\n        created_at: 100.days.ago, # Outside 90-day window\n        refunded_amount: 0.0,\n        transaction_type: \"payment\"\n      })\n    end\n    \n    it \"rejects refunds outside 90-day window\" do\n      expect(service).not_to be_valid\n      expect(service.errors[:end_to_end_id_original]).to include(/outside the 90-day refund window/)\n    end\n  end\nend